    if (typeof jsonSchema === "boolean")
        // no runtime value ever passes validation for JSON schema of 'false'
        return jsonSchema ? JsonSchemaScope.Json : type.never;
    if (Array.isArray(jsonSchema))
        return parseAnyOfJsonSchema(jsonSchema);
    const constAndOrEnumValidator = parseCommonJsonSchema(jsonSchema);
    const compositionValidator = parseCompositionJsonSchema(jsonSchema);
    const preTypeValidator = constAndOrEnumValidator ?
        compositionValidator ? compositionValidator.and(constAndOrEnumValidator)
