    if ("type" in jsonSchema) {
        const typeValidator = jsonSchemaTypeMatcher(jsonSchema);
        if (typeValidator === undefined) {
            throwParseError(writeJsonSchemaUnsupportedTypeMessage(printable(jsonSchema.type)));
