import { type } from "arktype"
import { roundTrip, exportJsonSchema } from "./src/roundTrip.ts"

const testCases = [
  {
    name: "Simple string",
    schemaDef: "string",
    corpus: ["hello", "", 123, null, {}]
  },
  {
    name: "Simple number",
    schemaDef: "number",
    corpus: [123, -1.5, 0, "123", null]
  },
  {
    name: "Integer",
    schemaDef: "number.integer",
    corpus: [123, 0, -5, 12.5, "123"]
  },
  {
    name: "Email string",
    schemaDef: "string.email",
    corpus: ["test@example.com", "user.name+tag@domain.co.uk", "invalid-email", 123]
  },
  {
    name: "Union string | number",
    schemaDef: "string|number",
    corpus: ["hello", 123, true, null]
  },
  {
    name: "Array of strings",
    schemaDef: "string[]",
    corpus: [["a", "b"], [], [1, 2], "not-an-array"]
  },
  {
    name: "Nested object with various fields",
    schemaDef: {
      id: "number.integer",
      profile: {
        username: "string",
        email: "string.email"
      },
      tags: "string[]"
    },
    corpus: [
      {
        id: 1,
        profile: {
          username: "alice",
          email: "alice@example.com"
        },
        tags: ["admin", "user"]
      },
      {
        id: 1.5, // invalid int
        profile: {
          username: "alice",
          email: "alice@example.com"
        },
        tags: ["admin", "user"]
      },
      {
        id: 1,
        profile: {
          username: "alice",
          email: "invalid-email" // invalid email
        },
        tags: ["admin", "user"]
      },
      {
        id: 1,
        profile: {
          username: "alice",
          email: "alice@example.com"
        },
        tags: [1, 2] // invalid tag type
      }
    ]
  }
]

let allPassed = true

for (const tc of testCases) {
  console.log(`\n--- Running Case: ${tc.name} ---`)
  try {
    const originalType = type(tc.schemaDef)
    const jsonSchema = exportJsonSchema(originalType)
    console.log("JSON Schema:", JSON.stringify(jsonSchema))

    const roundTrippedType = roundTrip(originalType)

    let casePassed = true
    for (let i = 0; i < tc.corpus.length; i++) {
      const payload = tc.corpus[i]
      const originalAccept = originalType.allows(payload)
      const roundTrippedAccept = roundTrippedType.allows(payload)
      const agree = originalAccept === roundTrippedAccept

      console.log(`  Payload [${i}]: ${JSON.stringify(payload)} -> Original: ${originalAccept}, RoundTripped: ${roundTrippedAccept}, Agree: ${agree}`)

      if (!agree) {
        casePassed = false
        allPassed = false
      }
    }

    if (casePassed) {
      console.log(`Result: PASS`)
    } else {
      console.error(`Result: FAIL`)
    }
  } catch (err) {
    console.error(`Error running case:`, err)
    allPassed = false
  }
}

if (allPassed) {
  console.log("\nALL TEST CASES PASSED!")
  process.exit(0)
} else {
  console.error("\nSOME TEST CASES FAILED!")
  process.exit(1)
}
